function AuthScreen() {
  const [mode,     setMode]     = useState("login");
  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [name,     setName]     = useState("");
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState("");
  const [success,  setSuccess]  = useState("");

  const reset = () => { setError(""); setSuccess(""); };

  const handleLogin = async () => {
    if (!email || !password) return setError("Preenche email e password.");
    setLoading(true); reset();
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setError(error.message === "Invalid login credentials"
      ? "Email ou password incorretos." : error.message);
    setLoading(false);
  };

  const handleRegister = async () => {
    if (!name || !email || !password) return setError("Preenche todos os campos.");
    if (password.length < 6) return setError("Password com mínimo 6 caracteres.");
    setLoading(true); reset();
    const { error } = await supabase.auth.signUp({
      email, password,
      options: { data: { name, role: "student" } }
    });
    if (error) setError(error.message);
    else setSuccess("Conta criada! Já podes entrar.");
    setLoading(false);
  };

  const handleForgot = async () => {
    if (!email) return setError("Introduz o teu email.");
    setLoading(true); reset();
    const { error } = await supabase.auth.resetPasswordForEmail(email);
    if (error) setError(error.message);
    else setSuccess("Email de recuperação enviado!");
    setLoading(false);
  };

  const inp = {
    width:"100%", background:T.card2, border:`1px solid ${T.border2}`,
    borderRadius:10, padding:"12px 16px", fontSize:14, color:T.text,
    outline:"none", boxSizing:"border-box", fontFamily:"inherit",
  };

  return (
    <div style={{ minHeight:"100vh", background:T.bg, display:"flex", alignItems:"center", justifyContent:"center", padding:20, fontFamily:"'Barlow',sans-serif" }}>
      <div style={{ width:"100%", maxWidth:420 }}>

        {/* Logo */}
        <div style={{ textAlign:"center", marginBottom:32 }}>
          <div style={{ display:"inline-flex", alignItems:"center", gap:12, background:T.navy, borderRadius:16, padding:"16px 28px" }}>
            <div style={{ width:44, height:44, background:`linear-gradient(135deg,${T.gold},${T.goldL})`, borderRadius:10, display:"flex", alignItems:"center", justifyContent:"center", fontSize:26, fontWeight:900, color:"#fff" }}>N</div>
            <div>
              <div style={{ fontSize:20, fontWeight:900, color:"#fff", letterSpacing:1 }}>notelab</div>
              <div style={{ fontSize:9, color:T.gold, letterSpacing:2, fontFamily:"monospace" }}>SCIENCE ACADEMY</div>
            </div>
          </div>
          <div style={{ color:T.text3, fontSize:12, marginTop:12 }}>Rigor que te leva mais longe.</div>
        </div>

        {/* Card */}
        <div style={{ background:T.surface, borderRadius:20, padding:"32px 28px", boxShadow:"0 8px 32px rgba(26,39,68,0.12)", border:`1px solid ${T.border}` }}>

          {mode !== "forgot" && (
            <div style={{ display:"flex", gap:4, marginBottom:24, background:T.card2, borderRadius:10, padding:4 }}>
              {[{id:"login",l:"Entrar"},{id:"register",l:"Criar conta"}].map(t=>(
                <button key={t.id} onClick={()=>{setMode(t.id);reset();}}
                  style={{ flex:1, background:mode===t.id?T.surface:"transparent", border:"none", borderRadius:8, padding:"9px", fontSize:13, fontWeight:mode===t.id?700:400, color:mode===t.id?T.navy:T.text2, cursor:"pointer", boxShadow:mode===t.id?"0 2px 6px rgba(0,0,0,0.08)":"none" }}>
                  {t.l}
                </button>
              ))}
            </div>
          )}

          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            {mode === "forgot" && (
              <div style={{ marginBottom:4 }}>
                <div style={{ fontSize:16, fontWeight:700, color:T.navy }}>Recuperar password</div>
                <div style={{ fontSize:12, color:T.text2, marginTop:4 }}>Envia-te um link para redefinires a password.</div>
              </div>
            )}

            {mode === "register" && (
              <input style={inp} placeholder="O teu nome completo" value={name} onChange={e=>setName(e.target.value)} />
            )}

            <input style={inp} type="email" placeholder="Email" value={email} onChange={e=>setEmail(e.target.value)} />

            {mode !== "forgot" && (
              <input style={inp} type="password" placeholder="Password (mínimo 6 caracteres)" value={password}
                onChange={e=>setPassword(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&(mode==="login"?handleLogin():handleRegister())} />
            )}

            {error && (
              <div style={{ background:"#fff5f5", border:"1px solid #fecaca", borderRadius:8, padding:"10px 14px", fontSize:12, color:T.red }}>⚠️ {error}</div>
            )}
            {success && (
              <div style={{ background:"#f0fdf4", border:"1px solid #86efac", borderRadius:8, padding:"10px 14px", fontSize:12, color:T.green }}>✓ {success}</div>
            )}

            <button
              disabled={loading}
              onClick={mode==="login"?handleLogin:mode==="register"?handleRegister:handleForgot}
              style={{ width:"100%", background:`linear-gradient(135deg,${T.navy},${T.navy2})`, border:"none", borderRadius:10, padding:"13px", color:"#fff", fontSize:14, fontWeight:700, cursor:"pointer", opacity:loading?.6:1 }}>
              {loading ? "A processar..." : mode==="login" ? "Entrar →" : mode==="register" ? "Criar conta →" : "Enviar email →"}
            </button>

            {mode === "login" && (
              <button onClick={()=>{setMode("forgot");reset();}}
                style={{ background:"none", border:"none", color:T.text3, fontSize:12, cursor:"pointer" }}>
                Esqueci a password
              </button>
            )}
            {mode === "forgot" && (
              <button onClick={()=>{setMode("login");reset();}}
                style={{ background:"none", border:"none", color:T.text3, fontSize:12, cursor:"pointer" }}>
                ← Voltar ao login
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}








